POST /premissa/selecionar
Payload: { premissa_id: uuid }
Disparado pelo frontend ao selecionar uma premissa.

parameters.jsCode:
// ===================================================================
// NORMALIZAR INPUT — Módulo 02A
// ===================================================================
// Aceita input do Manual Trigger (json.premissa_id)
// ou do Webhook (json.body.premissa_id).
// Saída unificada: { premissa_id: uuid }
// ===================================================================

const item = $input.first().json;
const premissa_id = item.premissa_id || (item.body && item.body.premissa_id) || null;

if (!premissa_id) {
  throw new Error('premissa_id não encontrado no input.');
}

return [{ json: { premissa_id } }];

// ===================================================================
// PARSE ROTEIROS — Módulo 02A
// ===================================================================
// Extrai as 3 opções do response do Claude.
// Cada opção vira um item separado para o loop.
// ===================================================================

const response = $input.first().json;
const videoId = $('Preparar Prompt').first().json._videoId;

let opcoes = [];

try {
  const text = response.text || response.response || '';
  const clean = text.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(clean);
  opcoes = parsed.opcoes || [];
} catch (e) {
  // Se falhar o parse, tenta encontrar o JSON no texto
  const text = response.text || response.response || '';
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      const parsed = JSON.parse(match[0]);
      opcoes = parsed.opcoes || [];
    } catch (e2) {
      // Parse falhou completamente
    }
  }
}

if (opcoes.length === 0) {
  return [{ json: { _erro: true, _videoId: videoId, _msg: 'Claude não retornou opções válidas' } }];
}

return opcoes.map((opcao, idx) => ({
  json: {
    ...opcao,
    _opcaoNumero: idx + 1,
    _videoId: videoId,
    _erro: false
  }
}));

// ===================================================================
// CHECK ERRO PARSE — Módulo 02A
// ===================================================================
// Se erro, retorna 1 item de erro.
// Se OK, passa as 3 opções originais adiante.
// ===================================================================

const items = $input.all();
const primeiro = items[0].json;

if (primeiro._erro) {
  return [{ json: { _erro: true, _videoId: primeiro._videoId, _totalOpcoes: 0 } }];
}

// Sem erro — passar as opções originais para o loop
return items;

// ===================================================================
// VALIDAR OPÇÃO — Módulo 02A v3.2-simplicidade
// Schema: 20 regras + Princípio Mestre + 5 campos recuperados
// (continuidade, transicao_entrada, perspectiva, hook_tipo, arco_narrativo)
// + objeto_recorrente OPCIONAL + tipo_cena com 4 valores válidos
// + coerência tipo_cena × personagem_presente
// Lê tags válidas do nó "Ler Tags Banco" pra checar efeitos_sonoros.
// ===================================================================

const opcao = $('Loop Opções').first().json;
const erros = [];
const avisos = [];

// --- Tags válidas do banco_efeitos ---
const efeitosRaw = $('Ler Tags Banco').all().map(i => i.json);
const listaEfeitos = efeitosRaw.length === 1 && Array.isArray(efeitosRaw[0]) ? efeitosRaw[0] : efeitosRaw;
const tagsValidas = new Set(listaEfeitos.filter(e => e && e.tag).map(e => e.tag));

// --- Campos topo obrigatórios (objeto_recorrente removido — agora opcional) ---
const camposTopo = ['titulo','thumbnail_conceito','numero_declarado_cenas',
  'loop_tipo','caption','hashtags','comentario_isca','sinopse','tom','texto_final_tela','cenas'];
for (const c of camposTopo) {
  if (opcao[c] === undefined || opcao[c] === null || opcao[c] === '') erros.push(`Campo ${c} ausente`);
}

// --- titulo ---
if (typeof opcao.titulo === 'string' && opcao.titulo.length > 45) {
  erros.push(`titulo > 45 chars (${opcao.titulo.length})`);
}

// --- loop_tipo ---
if (!['literal','tematico','invertido'].includes(opcao.loop_tipo)) {
  erros.push(`loop_tipo inválido: ${opcao.loop_tipo}`);
}

// --- objeto_recorrente (opcional — só valida estrutura quando declarado) ---
const objR = opcao.objeto_recorrente;
if (objR && (!objR.nome || !Array.isArray(objR.transformacoes) || objR.transformacoes.length !== 3)) {
  erros.push(`objeto_recorrente.transformacoes deve ter 3 itens quando declarado`);
}

// --- hashtags ---
const tags = opcao.hashtags;
if (!Array.isArray(tags) || tags.length !== 5) {
  erros.push(`hashtags deve ter exatamente 5 (tem ${Array.isArray(tags)?tags.length:'?'})`);
} else {
  if (tags[0] !== '#MundodeClay') erros.push(`hashtags[0] deve ser #MundodeClay`);
  if (tags[4] !== '#shorts') erros.push(`hashtags[4] deve ser #shorts`);
}

// --- caption 3 linhas ---
if (typeof opcao.caption === 'string') {
  const linhas = opcao.caption.split('\n').filter(l => l.trim().length > 0);
  if (linhas.length !== 3) erros.push(`caption deve ter 3 linhas (tem ${linhas.length})`);
}

// --- cenas ---
const cenas = Array.isArray(opcao.cenas) ? opcao.cenas : [];
const cenasReais = cenas.filter(c => (c?.tipo_cena ?? 'personagem') !== 'texto');
const cenasReaisCount = cenasReais.length;

if (cenasReaisCount < 8 || cenasReaisCount > 11) {
  erros.push(`Número de cenas reais fora do range 8-11 (tem ${cenasReaisCount})`);
}
// Auto-corrigir numero_declarado_cenas (Claude às vezes confunde total com narrativas)
if (Number(opcao.numero_declarado_cenas) !== cenasReaisCount) {
  avisos.push(`numero_declarado_cenas (${opcao.numero_declarado_cenas}) != count real (${cenasReaisCount}) — auto-corrigido`);
  opcao.numero_declarado_cenas = cenasReaisCount;
}

// --- objeto_recorrente em ≥3 cenas (só roda quando declarado) ---
if (objR?.nome) {
  const palavras = String(objR.nome).toLowerCase().split(/\s+/).filter(p => p.length > 2);
  const ocorrencias = cenas.filter(c => {
    const vis = (c?.descricao_visual || '').toLowerCase();
    return palavras.some(p => vis.includes(p));
  }).length;
  if (ocorrencias < 3) avisos.push(`objeto_recorrente "${objR.nome}" aparece em ${ocorrencias} cenas (esperado ≥3 quando declarado)`);
}

// --- money_shot, respiro_falso, ameaca_falsa ---
const moneyShots = cenas.filter(c => c?.cena_money_shot === true).length;
if (moneyShots !== 1) erros.push(`Deve haver exatamente 1 cena_money_shot (tem ${moneyShots})`);

const respiros = cenas.filter(c => c?.funcao_narrativa === 'respiro_falso').length;
if (respiros < 1) erros.push(`Deve haver ≥1 cena com funcao_narrativa "respiro_falso"`);

const ameacas = cenas.filter(c => c?.funcao_narrativa === 'ameaca_falsa').length;
if (ameacas < 1) erros.push(`Deve haver ≥1 cena com funcao_narrativa "ameaca_falsa"`);

// --- cena 1 ---
if (cenas[0] && !cenas[0].cena_1_frame_zero) {
  erros.push(`Cena 1: cena_1_frame_zero ausente`);
}

// --- ancora_sensorial em ≥1 cena ---
const ancoras = cenas.filter(c => c?.ancora_sensorial && String(c.ancora_sensorial).trim().length > 0).length;
if (ancoras < 1) erros.push(`Pelo menos 1 cena deve ter ancora_sensorial preenchida`);

// --- por cena ---
const tiposCenaValidos = ['personagem','ambiente','ameaca','texto'];
const emocoesValidas = ['calma','neutra','tensa','suspense','panico'];
const verbosProibidos = /\b(vejo|olho|observo|aparece|surge|mostra|encontro|noto|percebo)\b/i;
const pronomes1pessoa = /\b(eu|meu|minha|meus|minhas|me|mim|comigo|n[oó]s|nosso|nossa)\b/i;

// --- Auto-corrigir typos comuns do Claude nos nomes de campo ---
for (const c of cenas) {
  const typos = ['efeitos_sonores','efeitos_sonors','efeito_sonoro','efeitos_sonoro'];
  for (const t of typos) {
    if (c[t] !== undefined && c.efeitos_sonoros === undefined) {
      c.efeitos_sonoros = c[t];
      delete c[t];
    }
  }
}

for (let i = 0; i < cenas.length; i++) {
  const c = cenas[i];
  const n = i + 1;

  if (!tiposCenaValidos.includes(c?.tipo_cena)) erros.push(`Cena ${n}: tipo_cena inválido (${c?.tipo_cena})`);

  // Coerência dura: tipo_cena × personagem_presente
  if (c?.tipo_cena === 'personagem' && c?.personagem_presente !== true) {
    erros.push(`Cena ${n}: tipo_cena="personagem" exige personagem_presente=true (recebeu ${c?.personagem_presente})`);
  }
  if (c?.tipo_cena && c.tipo_cena !== 'personagem' && c?.personagem_presente === true) {
    erros.push(`Cena ${n}: tipo_cena="${c.tipo_cena}" exige personagem_presente=false (recebeu true)`);
  }

  // Continuidade: cena 1 nunca pode ter continuidade=true
  if (n === 1 && c?.continuidade === true) {
    erros.push(`Cena ${n}: cena 1 não pode ter continuidade=true (não existe cena anterior)`);
  }

  if (!emocoesValidas.includes(c?.emocao)) erros.push(`Cena ${n}: emocao inválida (${c?.emocao})`);

  if (c?.tipo_cena === 'texto') continue; // texto pula validações de narrativa

  if (c?.descricao_visual === undefined || c?.descricao_visual === null || c.descricao_visual === '') {
    erros.push(`Cena ${n}: descricao_visual ausente`);
  }
  if (c?.narracao === undefined || c?.narracao === null) {
    erros.push(`Cena ${n}: campo narracao ausente (use "" para silêncio)`);
  } else if (c.narracao && verbosProibidos.test(c.narracao)) {
    erros.push(`Cena ${n}: narração contém verbo proibido (vejo/olho/aparece/etc)`);
  } else if (c.narracao && pronomes1pessoa.test(c.narracao)) {
    erros.push(`Cena ${n}: narração em 1ª pessoa (proibido — usar 3ª pessoa sempre)`);
  } else if (c.narracao) {
    const palavras = c.narracao.trim().split(/\s+/).length;
    if (palavras > 28) {
      erros.push(`Cena ${n}: narração muito longa (${palavras} palavras, máx 28)`);
    } else if (palavras > 18) {
      avisos.push(`Cena ${n}: narração no limite (${palavras} palavras, ideal ≤18)`);
    }
  }

  // prompt_movimento_wan: 2 beats
  const pmw = c?.prompt_movimento_wan || '';
  if (!/Beat 1/i.test(pmw) || !/Beat 2/i.test(pmw)) {
    erros.push(`Cena ${n}: prompt_movimento_wan deve conter "Beat 1" e "Beat 2"`);
  }

  // efeitos_sonoros
  const efx = c?.efeitos_sonoros;
  if (!Array.isArray(efx)) {
    erros.push(`Cena ${n}: efeitos_sonoros deve ser array`);
  } else {
    for (let j = 0; j < efx.length; j++) {
      const e = efx[j];
      if (e?.tipo !== 'banco') erros.push(`Cena ${n} efeito ${j+1}: tipo deve ser "banco" (stable_audio proibido)`);
      if (!e?.tag) erros.push(`Cena ${n} efeito ${j+1}: tag ausente`);
      else if (!tagsValidas.has(e.tag)) avisos.push(`Cena ${n} efeito ${j+1}: tag "${e.tag}" fora do banco — upload manual no preview antes do M06`);
      if (typeof e?.weight !== 'number' || e.weight < 0.1 || e.weight > 1.0) {
        erros.push(`Cena ${n} efeito ${j+1}: weight fora do range 0.1-1.0`);
      }
    }
  }
}

const _invalida = erros.length > 0;
return [{
  json: {
    ...opcao,
    _invalida,
    _errosValidacao: erros,
    _avisosValidacao: avisos,
    _videoId: opcao._videoId,
    _opcaoNumero: opcao._opcaoNumero
  }
}];

// ===================================================================
// CONTAR VÁLIDAS — Módulo 02A
// ===================================================================
// Loop de opções concluído. Conta quantas foram salvas.
// ===================================================================

const videoId = $('Preparar Prompt').first().json._videoId;

return [{
  json: {
    video_id: videoId,
    mensagem: 'Opções de roteiro geradas e salvas.'
  }
}];

// ===================================================================
// GRAVAR OPÇÃO E CENAS — Módulo 02A v3.1
// Schema novo: aceita campos do prompt v3.1, mapeia descricao_visual→visual,
// grava campos novos (cena_money_shot, funcao_narrativa, etc), propaga erro
// via throw em vez de engolir, e atualiza videos.titulo na primeira gravação.
// ===================================================================

const opcao = $input.first().json;
const config = $('Configuração').first().json;
const videoId = opcao._videoId;
const baseUrl = config.SUPABASE_URL;
const apiKey = config.SUPABASE_SERVICE_KEY;

const headers = {
  'apikey': apiKey,
  'Authorization': `Bearer ${apiKey}`,
  'Content-Type': 'application/json'
};

// ============ 1. Gravar opção em roteiro_opcoes ============
let opcaoId = null;
try {
  const opcaoRes = await this.helpers.httpRequest({
    method: 'POST',
    url: `${baseUrl}/rest/v1/roteiro_opcoes`,
    headers: { ...headers, 'Prefer': 'return=representation' },
    body: {
      video_id: videoId,
      opcao_numero: opcao._opcaoNumero,
      roteiro_json: opcao,
      status: 'pendente',
      // v3.1 — campos topo
      titulo: opcao.titulo,
      caption: opcao.caption,
      hashtags: opcao.hashtags,
      thumbnail_conceito: opcao.thumbnail_conceito,
      numero_declarado_cenas: opcao.numero_declarado_cenas,
      objeto_recorrente: opcao.objeto_recorrente,
      loop_tipo: opcao.loop_tipo,
      arco_narrativo: opcao.arco_narrativo || null,
      comentario_isca: opcao.comentario_isca,
      // preservados pro pipeline (M03/M08)
      sinopse: opcao.sinopse,
      tom: opcao.tom,
      texto_final_tela: opcao.texto_final_tela
    }
  });
  opcaoId = Array.isArray(opcaoRes) ? opcaoRes[0]?.id : opcaoRes?.id;
  if (!opcaoId) throw new Error(`Falha ao gravar opção: resposta sem id. ${JSON.stringify(opcaoRes)}`);
} catch (e) {
  throw new Error(`Erro gravando roteiro_opcoes: ${e.message}`);
}

// ============ 2. Gravar cenas ============
const cenas = Array.isArray(opcao.cenas) ? opcao.cenas : [];
const totalCenas = cenas.length;
let gravadas = 0;
const errosCenas = [];

for (let i = 0; i < cenas.length; i++) {
  const cena = cenas[i];
  const ordemNum = Number(cena.numero) || (i + 1);

  // efeitos_sonoros sempre array de objetos {tipo:"banco", tag, weight}
  let efx = cena.efeitos_sonoros || [];
  if (typeof efx === 'string') {
    try { efx = JSON.parse(efx); } catch (_) { efx = []; }
  }
  if (!Array.isArray(efx)) efx = [];

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${baseUrl}/rest/v1/cenas`,
      headers: { ...headers, 'Prefer': 'return=minimal' },
      body: {
        video_id: videoId,
        opcao_id: opcaoId,
        numero: String(ordemNum),
        ordem: ordemNum,
        // v3.1 — mapeamentos críticos
        visual: cena.descricao_visual || '',           // descricao_visual → visual
        prompt_movimento_wan: cena.prompt_movimento_wan || '',
        narracao: cena.narracao || '',
        emocao: cena.emocao || 'neutra',
        tipo_cena: cena.tipo_cena || 'personagem',     // fallback válido contra CHECK
        efeitos_sonoros: efx,
        som_ambiente: cena.som_ambiente || '',
        movimento: cena.movimento || '',
        personagem_presente: cena.personagem_presente !== undefined ? cena.personagem_presente : true,
        continuidade: cena.continuidade === true,
       transicao_entrada: (function() {
          // Forçar corte_seco nas 2 últimas cenas (penúltima narrativa + tela de texto final)
          // para produzir corte limpo no fechamento do vídeo.
          // ordemNum é 1-based, totalCenas é o count do array.
          const isPenultima = (ordemNum === totalCenas - 1);
          const isUltima = (ordemNum === totalCenas);
          if (isPenultima || isUltima) return 'corte_seco';
          // Demais cenas: Claude decidiu, fallback dip_to_black
          return cena.transicao_entrada || 'dip_to_black';
        })(),
        perspectiva: 'terceira_pessoa',
        hook_tipo: ordemNum === 1 ? (cena.hook_tipo || 'acao') : null,
        // v3.1 — campos novos (colunas adicionadas via migration)
        cena_money_shot: cena.cena_money_shot === true,
        cena_1_frame_zero: cena.cena_1_frame_zero || null,
        funcao_narrativa: cena.funcao_narrativa || null,
        ancora_sensorial: cena.ancora_sensorial || null,
        // duracao fixa do canal (5s por cena, regra do pipeline)
        duracao_estimada: 5.0
              }
    });
    gravadas++;
  } catch (e) {
    errosCenas.push(`Cena ${ordemNum}: ${e.message}`);
  }
}

// ============ 3. Propaga erro se gravação parcial ============
if (gravadas !== cenas.length) {
  throw new Error(
    `Gravação parcial de cenas: ${gravadas}/${cenas.length}. ` +
    `Erros: ${errosCenas.join(' | ')}`
  );
}

// ============ 4. Atualizar videos.titulo na 1ª opção gravada ============
// Só na opção 1 pra evitar sobrescrever (todas as 3 podem chegar aqui).
if (opcao._opcaoNumero === 1 && opcao.titulo) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${baseUrl}/rest/v1/videos?id=eq.${videoId}`,
      headers: { ...headers, 'Prefer': 'return=minimal' },
      body: { titulo: opcao.titulo }
    });
  } catch (e) {
    // Não bloqueia: M02B pode atualizar depois quando humano aprovar.
    console.log(`Aviso: falha ao atualizar videos.titulo: ${e.message}`);
  }
}

return [{
  json: {
    _opcaoId: opcaoId,
    _opcaoNumero: opcao._opcaoNumero,
    _cenasGravadas: gravadas,
    _cenasTotal: cenas.length
  }
}];

